import React, { useState, useEffect } from 'react';
import axios from 'axios';
import '../../Styles/AdminStyle.css'; // Ensure this is imported if it's not already

const CareTipManager = () => {
  const [tips, setTips] = useState([]);
  const [tip, setTip] = useState({
    title: '',
    topic: '',
    summary: '',
    content: '',
    image: '',
  });

  const [editingId, setEditingId] = useState(null);

  const fetchTips = async () => {
    const res = await axios.get('http://localhost:5000/api/caretips');
    setTips(res.data);
  };

  useEffect(() => {
    fetchTips();
  }, []);

  const handleChange = (e) => {
    setTip({ ...tip, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (editingId) {
        await axios.put(`http://localhost:5000/api/caretips/${editingId}`, tip);
        setEditingId(null);
      } else {
        await axios.post('http://localhost:5000/api/caretips', tip);
      }
      setTip({ title: '', topic: '', summary: '', content: '', image: '' });
      fetchTips();
    } catch (err) {
      alert('Error saving care tip');
    }
  };

  const handleEdit = (t) => {
    setTip({
      title: t.title,
      topic: t.topic,
      summary: t.summary,
      content: t.content,
      image: t.image,
    });
    setEditingId(t._id);
  };

  const handleDelete = async (id) => {
    if (window.confirm('Delete this tip?')) {
      await axios.delete(`http://localhost:5000/api/caretips/${id}`);
      fetchTips();
    }
  };

  return (
    <div className="admin-dashboard">
      <div className="caretip-container">
        <h2>{editingId ? 'Edit' : 'Add'} Care Tip</h2>
        <form onSubmit={handleSubmit}>
          <input
            name="title"
            placeholder="Title"
            value={tip.title}
            onChange={handleChange}
            required
          />
          <input
            name="topic"
            placeholder="Topic (Watering, Light, etc.)"
            value={tip.topic}
            onChange={handleChange}
            required
          />
          <input
            name="summary"
            placeholder="Summary"
            value={tip.summary}
            onChange={handleChange}
            required
          />
          <textarea
            name="content"
            placeholder="Full Content"
            value={tip.content}
            onChange={handleChange}
            required
          />
          <input
            name="image"
            placeholder="Image URL"
            value={tip.image}
            onChange={handleChange}
          />
          <button type="submit">
            {editingId ? 'Update' : 'Add'} Tip
          </button>
        </form>
      </div>

      <div className="caretip-container caretip-list">
        <h3>All Tips</h3>
        <ul>
          {tips.map((t) => (
            <li key={t._id}>
              <span>
                <strong>{t.title}</strong> ({t.topic})
              </span>
              <span>
                <button onClick={() => handleEdit(t)}>Edit</button>
                <button onClick={() => handleDelete(t._id)}>Delete</button>
              </span>
            </li>
          ))}
        </ul>
      </div>
    </div>
  );
};

export default CareTipManager;
